return ['domain'=>'agnosis','plural-forms'=>'nplurals=2; plural=n != 1;','language'=>'en_US','project-id-version'=>'Agnosis 0.9.21','pot-creation-date'=>'2026-07-13T22:58+00:00','po-revision-date'=>'2026-07-12 17:17+0000','x-generator'=>'Loco https://localise.biz/','messages'=>['Agnosis'=>'Agnosis','https://agnosis.art'=>'https://agnosis.art','Art blooming out of oblivion. Email your art, AI polishes it, the world sees it. A free, federated publishing network for independent artists.'=>'Art blooming out of oblivion. Email your art, AI polishes it, the world sees it. A free, federated publishing network for independent artists.','Agnosis requires PHP %s or higher.'=>'Agnosis requires PHP %s or higher.','Agnosis requires WordPress %s or higher.'=>'Agnosis requires WordPress %s or higher.','Filter by medium'=>'Filter by medium','All'=>'All','Enlarged image'=>'Enlarged image','Featured'=>'Featured','Enlarge'=>'Enlarge','Gallery pages'=>'Gallery pages','Prev'=>'Prev','Next'=>'Next','Contact Messages'=>'Contact Messages','No contact messages yet.'=>'No contact messages yet.','No messages match this filter.'=>'No messages match this filter.','#'=>'#','Artist'=>'Artist','From'=>'From','Message'=>'Message','Status'=>'Status','Received'=>'Received','Actions'=>'Actions','(deleted artist #%d)'=>'(deleted artist #%d)','You do not have permission to perform this action.'=>'You do not have permission to perform this action.','Message deleted.'=>'Message deleted.','All statuses'=>'All statuses','Sent'=>'Sent','Rejected'=>'Rejected','Filter'=>'Filter','Reset'=>'Reset','Page %1$d of %2$d'=>'Page %1$d of %2$d','Previous'=>'Previous','Delete this message?'=>'Delete this message?','Delete'=>'Delete','just now'=>'just now','%dm ago'=>'%dm ago','%dh ago'=>'%dh ago','Mail from (workflow)'=>'Mail from (workflow)','Newsletter'=>'Newsletter','Agnosis Inbox'=>'Agnosis Inbox','Inbox'=>'Inbox','No messages in the queue yet. Click "Poll Inbox" to fetch messages from your IMAP account.'=>'No messages in the queue yet. Click "Poll Inbox" to fetch messages from your IMAP account.','No queue rows match this filter.'=>'No queue rows match this filter.','Subject'=>'Subject','Endpoint'=>'Endpoint','Files'=>'Files','Error'=>'Error','unregistered sender'=>'unregistered sender','Old row — delete and re-poll to preview'=>'Old row — delete and re-poll to preview','Attachment viewer'=>'Attachment viewer','Close'=>'Close','Queue row deleted. Poll Inbox to re-fetch the message.'=>'Queue row deleted. Poll Inbox to re-fetch the message.','Queue #%d sent to pipeline. Check back in a few seconds.'=>'Queue #%d sent to pipeline. Check back in a few seconds.','Poll complete. %d new message(s) added to the queue.'=>'Poll complete. %d new message(s) added to the queue.','Force-reprocess: %1$d row(s) reset, %2$d new message(s) enqueued.'=>'Force-reprocess: %1$d row(s) reset, %2$d new message(s) enqueued.','Processed %d pending item(s).'=>'Processed %d pending item(s).','Pending'=>'Pending','Processing'=>'Processing','Published'=>'Published','Failed'=>'Failed','Skipped'=>'Skipped','All reasons'=>'All reasons','%1$d message from an unregistered sender is hidden from this view. <a href="%2$s">View it</a>.'=>'%1$d message from an unregistered sender is hidden from this view. <a href="%2$s">View it</a>.' . "\0" . '%1$d messages from unregistered senders are hidden from this view. <a href="%2$s">View them</a>.','Poll Inbox'=>'Poll Inbox','Force Reprocess'=>'Force Reprocess','Process All Pending'=>'Process All Pending','Goodbye'=>'Goodbye','Community'=>'Community','Bounce'=>'Bounce','Awaiting Review'=>'Awaiting Review','Live'=>'Live','Processed'=>'Processed','Member Removed'=>'Member Removed','Broadcast Sent'=>'Broadcast Sent','Bounced (too long)'=>'Bounced (too long)','Handled'=>'Handled','Process'=>'Process','View Post'=>'View Post','Reprocess'=>'Reprocess','Running…'=>'Running…','Delete this queue row?'=>'Delete this queue row?','Configuration'=>'Configuration','Force-reprocess complete. %1$d queue row(s) reset, %2$d new message(s) enqueued. Click "Process Pending Queue" to run the AI pipeline.'=>'Force-reprocess complete. %1$d queue row(s) reset, %2$d new message(s) enqueued. Click "Process Pending Queue" to run the AI pipeline.','Log cleared.'=>'Log cleared.','Debug files cleared. %d file was removed.'=>'Debug files cleared. %d file was removed.' . "\0" . 'Debug files cleared. %d files were removed.','Term translation cache cleared. Terms will be re-translated the next time they\'re needed.'=>'Term translation cache cleared. Terms will be re-translated the next time they\'re needed.','Processed %d pending queue item(s). Check the Logs tab for details.'=>'Processed %d pending queue item(s). Check the Logs tab for details.','Poll complete. %d new message(s) enqueued. Check the Logs tab, then click Process Pending Queue.'=>'Poll complete. %d new message(s) enqueued. Check the Logs tab, then click Process Pending Queue.','Applicant admitted. A welcome email has been sent.'=>'Applicant admitted. A welcome email has been sent.','Could not admit — the application may no longer be pending.'=>'Could not admit — the application may no longer be pending.','Application rejected.'=>'Application rejected.','Could not reject — the application may no longer be pending.'=>'Could not reject — the application may no longer be pending.','Artist suspended. A notification email has been sent.'=>'Artist suspended. A notification email has been sent.','Could not suspend the artist — they may no longer be active.'=>'Could not suspend the artist — they may no longer be active.','Artist permanently deleted. Their account and all content have been removed.'=>'Artist permanently deleted. Their account and all content have been removed.','Could not delete the artist — please try again.'=>'Could not delete the artist — please try again.','Community removal vote opened. All artists have been emailed.'=>'Community removal vote opened. All artists have been emailed.','Could not open a removal vote — one may already be active for this artist.'=>'Could not open a removal vote — one may already be active for this artist.','Issue prepared and queued — it will go out over the next few cron cycles.'=>'Issue prepared and queued — it will go out over the next few cron cycles.','Could not start this issue — a previous one may still be sending.'=>'Could not start this issue — a previous one may still be sending.','Test email sent — check the inbox you sent it to.'=>'Test email sent — check the inbox you sent it to.','Could not send the test email — check the address and your site\'s outgoing mail configuration.'=>'Could not send the test email — check the address and your site\'s outgoing mail configuration.','Invitation sent.'=>'Invitation sent.','Could not send the invitation — check the address and your site\'s outgoing mail configuration.'=>'Could not send the invitation — check the address and your site\'s outgoing mail configuration.','Test invitation sent — check the inbox you sent it to.'=>'Test invitation sent — check the inbox you sent it to.','Could not send the test invitation — check the address and your site\'s outgoing mail configuration.'=>'Could not send the test invitation — check the address and your site\'s outgoing mail configuration.','Test email sent — check whether it lands in your inbox or your spam folder.'=>'Test email sent — check whether it lands in your inbox or your spam folder.','Failed recipients reset to pending — they will be retried on the next few cron cycles.'=>'Failed recipients reset to pending — they will be retried on the next few cron cycles.','No failed recipients to retry for this newsletter.'=>'No failed recipients to retry for this newsletter.','Art blooming out of oblivion'=>'Art blooming out of oblivion','Save Changes'=>'Save Changes','Members'=>'Members','Rules'=>'Rules','General'=>'General','Email Inbox'=>'Email Inbox','AI Providers'=>'AI Providers','Behavior'=>'Behavior','Network'=>'Network','Commerce'=>'Commerce','Logs'=>'Logs','— None (inline message only) —'=>'— None (inline message only) —','Reset to default'=>'Reset to default','Replaces the text above with the plugin\'s built-in default — click Save Changes below to keep it.'=>'Replaces the text above with the plugin\'s built-in default — click Save Changes below to keep it.','Select Image'=>'Select Image','Remove'=>'Remove','Base domain'=>'Base domain','Root domain for artist subdomains, e.g. agnosis.art. Each artist is reachable at nicename.{base_domain}. Requires a wildcard DNS record (*.{base_domain}) pointing to this server. Leave blank to disable subdomain routing.'=>'Root domain for artist subdomains, e.g. agnosis.art. Each artist is reachable at nicename.{base_domain}. Requires a wildcard DNS record (*.{base_domain}) pointing to this server. Leave blank to disable subdomain routing.','Debug logging'=>'Debug logging','Writes raw diagnostic dumps of the email intake pipeline (message structure, attachment MIME detection, media conversion, post creation) to a dedicated debug directory — far more detail than the Logs tab keeps, for tracing exactly where a submission was rejected or lost. Turn off once you have what you need; files can accumulate quickly. Can also be forced from wp-config.php with `define( \'AGNOSIS_DEBUG\', true );`, which overrides this toggle. See the Debug Files panel below for the directory location and a clear-files button.'=>'Writes raw diagnostic dumps of the email intake pipeline (message structure, attachment MIME detection, media conversion, post creation) to a dedicated debug directory — far more detail than the Logs tab keeps, for tracing exactly where a submission was rejected or lost. Turn off once you have what you need; files can accumulate quickly. Can also be forced from wp-config.php with `define( \'AGNOSIS_DEBUG\', true );`, which overrides this toggle. See the Debug Files panel below for the directory location and a clear-files button.','Debug file retention (days)'=>'Debug file retention (days)','Debug dumps older than this are permanently deleted by the daily cleanup — automatically, whether or not debug logging is currently turned on, so files left over from a past debug session don\'t linger indefinitely. A dump is a full raw copy of an artist\'s email, so this defaults shorter than the inbox/queue retention above. Default: 14 days.'=>'Debug dumps older than this are permanently deleted by the daily cleanup — automatically, whether or not debug logging is currently turned on, so files left over from a past debug session don\'t linger indefinitely. A dump is a full raw copy of an artist\'s email, so this defaults shorter than the inbox/queue retention above. Default: 14 days.','Email logo'=>'Email logo','Shown in the header of outgoing HTML emails (submission review, removal confirmation, rejection notice, and both newsletters) in place of the plain "✦ Site Name" text. Leave empty to keep the text wordmark. Displayed at up to 40px tall — any width or aspect ratio works.'=>'Shown in the header of outgoing HTML emails (submission review, removal confirmation, rejection notice, and both newsletters) in place of the plain "✦ Site Name" text. Leave empty to keep the text wordmark. Displayed at up to 40px tall — any width or aspect ratio works.','Preset biography title'=>'Preset biography title','When set, every artist\'s biography page uses this exact title instead of their own, regardless of what the artist submitted, edited on their approve form, or later changed on their published page. Leave blank to keep using each artist\'s own title (the default). Shown exactly as typed here on every language version of a biography page — not machine-translated per language. See "Include artist\'s name in preset title" below.'=>'When set, every artist\'s biography page uses this exact title instead of their own, regardless of what the artist submitted, edited on their approve form, or later changed on their published page. Leave blank to keep using each artist\'s own title (the default). Shown exactly as typed here on every language version of a biography page — not machine-translated per language. See "Include artist\'s name in preset title" below.','Include artist\'s name in preset title'=>'Include artist\'s name in preset title','When the preset title above is set, append the artist\'s own WordPress display name to it (e.g. "Meet the Artist — Jane Doe"). Has no effect while the preset title is blank.'=>'When the preset title above is set, append the artist\'s own WordPress display name to it (e.g. "Meet the Artist — Jane Doe"). Has no effect while the preset title is blank.','Cloudflare Turnstile site key'=>'Cloudflare Turnstile site key','From your Cloudflare Turnstile widget (dash.cloudflare.com → Turnstile). Adds a human-verification check to the public Subscribe (newsletter-signup) and Join forms. Leave either key blank to leave both forms exactly as they are today.'=>'From your Cloudflare Turnstile widget (dash.cloudflare.com → Turnstile). Adds a human-verification check to the public Subscribe (newsletter-signup) and Join forms. Leave either key blank to leave both forms exactly as they are today.','Cloudflare Turnstile secret key'=>'Cloudflare Turnstile secret key','Kept server-side only — used to verify each form submission directly with Cloudflare before it is accepted.'=>'Kept server-side only — used to verify each form submission directly with Cloudflare before it is accepted.','Email driver'=>'Email driver','Name shown as the sender of admission, vote, welcome, departure, invitation, and submission-review emails. Leave blank to use the site name.'=>'Name shown as the sender of admission, vote, welcome, departure, and other workflow emails. Leave blank to use the site name.','Mail from: email address'=>'Your email address','Dedicated From: address for admission, vote, welcome, departure, invitation, and submission-review emails — e.g. hello@agnosis.art. This is not one of the endpoint addresses below (submit@, bio@, community@, etc.) — those are where artists send mail in; this is who workflow mail appears to come from. Separate from the Settings → Newsletter sender, which only covers digest mail. Leave blank to use the admin email. Must be a valid, deliverable address on your domain (SPF/DKIM configured) or messages may be marked as spam.'=>'Dedicated From: address for admission, vote, welcome, departure, invitation, and submission-review emails — e.g. hello@agnosis.art. Deliberately separate from the Settings → Newsletter sender: these are one-off actions (a vote link, a review link), not digest mail. Leave blank to use the admin email. Must be a valid, deliverable address on your domain (SPF/DKIM configured) or messages may be marked as spam.','Artwork submissions address'=>'Artwork submissions address','Artists send artwork to this address — e.g. submit@agnosis.art'=>'Artists send artwork to this address — e.g. submit@agnosis.art','Biography submissions address'=>'Biography submissions address','Artists send biography updates to this address — e.g. bio@agnosis.art'=>'Artists send biography updates to this address — e.g. bio@agnosis.art','Event submissions address'=>'Event submissions address','Artists send event announcements to this address — e.g. event@agnosis.art'=>'Artists send event announcements to this address — e.g. event@agnosis.art','Replace artwork address'=>'Replace artwork address','Artist sends a new version of an existing artwork. Subject must match the original title. Bypasses duplicate detection — e.g. replace@agnosis.art'=>'Artist sends a new version of an existing artwork. Subject must match the original title. Bypasses duplicate detection — e.g. replace@agnosis.art','Removal request address'=>'Removal request address','Artist requests takedown of an existing artwork. Subject must match the title. Moves the post to draft pending admin review — e.g. remove@agnosis.art'=>'Artist requests takedown of an existing artwork. Subject must match the title. Moves the post to draft pending admin review — e.g. remove@agnosis.art','Promote artwork address'=>'Promote artwork address','Artist sends an email here (subject = exact artwork title) to choose which artwork represents them in the shared community gallery on the main site — not their own subdomain, which already shows everything they\'ve published. Any previously featured artwork is automatically demoted — e.g. promote@agnosis.art'=>'Artist sends an email here (subject = exact artwork title) to choose which artwork represents them in the shared community gallery on the main site — not their own subdomain, which already shows everything they\'ve published. Any previously featured artwork is automatically demoted — e.g. promote@agnosis.art','Photo-only address'=>'Photo-only address','Opt-out lane for photographers and lens-based artists whose photograph is the artwork, not a snapshot of it. Submissions here are published with the original image exactly as sent — AI enhancement is skipped and the quality-rejection gate is bypassed. AI description (title, tags, alt text) still runs. Use the [Photo] subject indicator as a fallback for mail clients that do not support To: aliases — e.g. photo@agnosis.art'=>'Opt-out lane for photographers and lens-based artists whose photograph is the artwork, not a snapshot of it. Submissions here are published with the original image exactly as sent — AI enhancement is skipped and the quality-rejection gate is bypassed. AI description (title, tags, alt text) still runs. Use the [Photo] subject indicator as a fallback for mail clients that do not support To: aliases — e.g. photo@agnosis.art','Pure address (no AI at all)'=>'Pure address (no AI at all)','Strictest opt-out lane: nothing sent here is touched by AI — no enhancement, no vision description, no rewriting. The published post title, body, and translated-title subtitle are taken verbatim from the artist\'s own subject and message text; the attached file(s) are published exactly as sent. The quality-rejection gate is bypassed, same as Photo-only. Use the [Pure] subject indicator as a fallback for mail clients that do not support To: aliases — e.g. pure@agnosis.art'=>'Strictest opt-out lane: nothing sent here is touched by AI — no enhancement, no vision description, no rewriting. The published post title, body, and translated-title subtitle are taken verbatim from the artist\'s own subject and message text; the attached file(s) are published exactly as sent. The quality-rejection gate is bypassed, same as Photo-only. Use the [Pure] subject indicator as a fallback for mail clients that do not support To: aliases — e.g. pure@agnosis.art','Goodbye / self-removal address'=>'Goodbye / self-removal address','Artist emails here (any subject, no attachment needed) to request account deletion. A confirmation link is emailed back before anything is deleted — e.g. goodbye@agnosis.art'=>'Artist emails here (any subject, no attachment needed) to request account deletion. A confirmation link is emailed back before anything is deleted — e.g. goodbye@agnosis.art','Community announcement address'=>'Community announcement address','Any active artist emails here (any subject, no attachment needed) to send a message to every other community member — e.g. community@agnosis.art. Never processed as a submission and never becomes a post: each recipient gets the subject and message translated into their own language, with the sender\'s name and email included so they can reply directly. Sent from the address configured under Settings → Community → Rules, which can be different from this one. Only works for a message sent by an active, admitted artist.'=>'Any active artist emails here (any subject, no attachment needed) to send a message to every other community member — e.g. community@agnosis.art. Never processed as a submission and never becomes a post: each recipient gets the subject and message translated into their own language, with the sender\'s name and email included so they can reply directly. Sent from the address configured under Settings → Community → Rules, which can be different from this one. Only works for a message sent by an active, admitted artist.','IMAP host'=>'IMAP host','e.g. imap.yourhost.com'=>'e.g. imap.yourhost.com','IMAP port'=>'IMAP port','Use SSL'=>'Use SSL','Skip SSL certificate validation'=>'Skip SSL certificate validation','⚠ Use only as a temporary workaround when your mail server\'s certificate is not yet trusted (e.g. Plesk self-signed cert before Let\'s Encrypt is applied to the mail daemon). Disable this once the mail server presents a valid certificate.'=>'⚠ Use only as a temporary workaround when your mail server\'s certificate is not yet trusted (e.g. Plesk self-signed cert before Let\'s Encrypt is applied to the mail daemon). Disable this once the mail server presents a valid certificate.','IMAP username'=>'IMAP username','Login username for the IMAP account — typically the catch-all mailbox address.'=>'Login username for the IMAP account — typically the catch-all mailbox address.','Submission email password'=>'Submission email password','Webhook secret'=>'Webhook secret','HMAC secret shared with your webhook provider (Mailgun, SendGrid…). Used for both the inbound-mail endpoint (/wp-json/agnosis/v1/email/inbound) and the bounce/complaint events endpoint (/wp-json/agnosis/v1/email/events) — point your provider\'s bounce/spam-complaint webhook at the latter to keep your subscriber and artist addresses clean.'=>'HMAC secret shared with your webhook provider (Mailgun, SendGrid…). Used for both the inbound-mail endpoint (/wp-json/agnosis/v1/email/inbound) and the bounce/complaint events endpoint (/wp-json/agnosis/v1/email/events) — point your provider\'s bounce/spam-complaint webhook at the latter to keep your subscriber and artist addresses clean.','Inbox retention (days)'=>'Inbox retention (days)','IMAP messages and processed/failed queue rows older than this are permanently deleted by the daily cleanup, whether read or unread. Default: 7 days.'=>'IMAP messages and processed/failed queue rows older than this are permanently deleted by the daily cleanup, whether read or unread. Default: 7 days.','Contact message retention (days)'=>'Contact message retention (days)','Visitor-to-artist contact messages (sent or rejected) older than this are permanently deleted by the daily cleanup. The visitor\'s IP address is cleared independently after 30 days regardless of this setting, once it\'s no longer useful for abuse investigation. Default: 90 days.'=>'Visitor-to-artist contact messages (sent or rejected) older than this are permanently deleted by the daily cleanup. The visitor\'s IP address is cleared independently after 30 days regardless of this setting, once it\'s no longer useful for abuse investigation. Default: 90 days.','Per-sender hourly submission limit'=>'Per-sender hourly submission limit','Maximum submissions accepted from a single artist per hour, across both IMAP and webhook intake. Exceeding this limit silently drops the message (no retry from ESPs). Default: 5.'=>'Maximum submissions accepted from a single artist per hour, across both IMAP and webhook intake. Exceeding this limit silently drops the message (no retry from ESPs). Default: 5.','Per-artist contact limit'=>'Per-artist contact limit','Maximum messages the same visitor (by email address) can send to a single artist within the window below — applies across every language version of that artist\'s page. Default: 2.'=>'Maximum messages the same visitor (by email address) can send to a single artist within the window below — applies across every language version of that artist\'s page. Default: 2.','Per-artist contact limit window (hours)'=>'Per-artist contact limit window (hours)','Time window, in hours, the per-artist contact limit above applies over. Also controls how long a visitor sees the "already contacted" notice instead of the form after messaging an artist. Default: 1 (one hour).'=>'Time window, in hours, the per-artist contact limit above applies over. Also controls how long a visitor sees the "already contacted" notice instead of the form after messaging an artist. Default: 1 (one hour).','Require SPF/DKIM authentication'=>'Require SPF/DKIM authentication','When enabled, intake messages must pass SPF or DKIM authentication (via the Authentication-Results header). Prevents spoofed From: addresses. Requires your ESP to include Authentication-Results headers and your domain to have SPF/DKIM records configured. Leave off if you are not sure — rejected legitimate mail is silent. Default: off.'=>'When enabled, intake messages must pass SPF or DKIM authentication (via the Authentication-Results header). Prevents spoofed From: addresses. Requires your ESP to include Authentication-Results headers and your domain to have SPF/DKIM records configured. Leave off if you are not sure — rejected legitimate mail is silent. Default: off.','Description provider'=>'Description provider','Analyzes the artwork image and writes the title, body, tags and alt text. WordPress AI Services delegates to whichever provider the site has configured via the AI Services plugin.'=>'Analyzes the artwork image and writes the title, body, tags and alt text. WordPress AI Services delegates to whichever provider the site has configured via the AI Services plugin.','OpenAI vision model'=>'OpenAI vision model','Model used for artwork description when OpenAI is the description provider. Must support vision input.'=>'Model used for artwork description when OpenAI is the description provider. Must support vision input.','Anthropic model'=>'Anthropic model','Model used for artwork description when Anthropic is the description provider. Must support vision input.'=>'Model used for artwork description when Anthropic is the description provider. Must support vision input.','OpenAI text model'=>'OpenAI text model','Cheap, fast model used for text-only tasks when OpenAI is the description provider — translating a submission into the site\'s primary language, and moderating contact-form messages. Does not need vision support.'=>'Cheap, fast model used for text-only tasks when OpenAI is the description provider — translating a submission into the site\'s primary language, and moderating contact-form messages. Does not need vision support.','Anthropic text model'=>'Anthropic text model','Cheap, fast model used for text-only tasks when Anthropic is the description provider — translating a submission into the site\'s primary language, and moderating contact-form messages. Does not need vision support.'=>'Cheap, fast model used for text-only tasks when Anthropic is the description provider — translating a submission into the site\'s primary language, and moderating contact-form messages. Does not need vision support.','Vision image max width (px)'=>'Vision image max width (px)','Images are downscaled proportionally to this width before being sent to the AI for description — vision token cost scales with resolution, and a description task needs far fewer pixels than the original photo. Applies to artwork photo uploads, rasterised PDF pages, and video poster frames alike. Set to 0 to always send full-resolution images (uses more tokens, no quality difference for typical description tasks). Requires the Imagick PHP extension; images are sent at their original size regardless of this setting when it is unavailable. Default: 800.'=>'Images are downscaled proportionally to this width before being sent to the AI for description — vision token cost scales with resolution, and a description task needs far fewer pixels than the original photo. Applies to artwork photo uploads, rasterized PDF pages, and video poster frames alike. Set to 0 to always send full-resolution images (uses more tokens, no quality difference for typical description tasks). Requires the Imagick PHP extension; images are sent at their original size regardless of this setting when it is unavailable. Default: 800.','Enhancement provider'=>'Enhancement provider','Auto (OpenAI if key is set)'=>'Auto (OpenAI if key is set)','Disabled — use original image'=>'Disabled — use original image','Enhances the artwork image before publishing. Uses OpenAI gpt-image-1. Set to Disabled to skip enhancement and publish the original.'=>'Enhances the artwork image before publishing. Uses OpenAI gpt-image-1. Set to Disabled to skip enhancement and publish the original.','OpenAI image model'=>'OpenAI image model','Model used for image enhancement when OpenAI is the enhancement provider.'=>'Model used for image enhancement when OpenAI is the enhancement provider.','Polish biography with AI'=>'Polish biography with AI','When enabled, biography submissions are passed through the AI to fix spelling and make minor text improvements before saving.'=>'When enabled, biography submissions are passed through the AI to fix spelling and make minor text improvements before saving.','Polish events with AI'=>'Polish events with AI','When enabled, event submissions are passed through the AI to fix spelling and make minor text improvements before saving.'=>'When enabled, event submissions are passed through the AI to fix spelling and make minor text improvements before saving.','Merge biography updates with AI'=>'Merge biography updates with AI','When enabled, biography updates are merged with the existing biography using AI — new information is integrated rather than replacing everything. Recommended: artists can send incremental updates ("I just won an award") without resubmitting their full bio. Disable to always replace the biography with the latest submission.'=>'When enabled, biography updates are merged with the existing biography using AI — new information is integrated rather than replacing everything. Recommended: artists can send incremental updates ("I just won an award") without resubmitting their full bio. Disable to always replace the biography with the latest submission.','Rejection threshold (quality score)'=>'Rejection threshold (quality score)','Photos scoring at or below this value (1–10) are automatically rejected — the artist receives a friendly email explaining the issue and is invited to resubmit. Score 0 disables automatic rejection. Must be lower than the enhancement threshold. Default: 3.'=>'Photos scoring at or below this value (1–10) are automatically rejected — the artist receives a friendly email explaining the issue and is invited to resubmit. Score 0 disables automatic rejection. Must be lower than the enhancement threshold. Default: 3.','Enhancement threshold (quality score)'=>'Enhancement threshold (quality score)','Photos scoring below this value (1–10) are automatically enhanced. Score 10 = perfect photograph, 1 = technically unusable. Default: 7 — only visibly problematic photos are processed. Set to 1 to disable automatic enhancement entirely.'=>'Photos scoring below this value (1–10) are automatically enhanced. Score 10 = perfect photograph, 1 = technically unusable. Default: 7 — only visibly problematic photos are processed. Set to 1 to disable automatic enhancement entirely.','OpenAI API key'=>'OpenAI API key','Required when OpenAI is the description or enhancement provider.'=>'Required when OpenAI is the description or enhancement provider.','Anthropic API key'=>'Anthropic API key','Required when Anthropic is the description provider.'=>'Required when Anthropic is the description provider.','Artwork display width (px)'=>'Artwork display width (px)','Width of the agnosis-artwork image size used in post content and lightbox. Height scales proportionally. Default: 1920. Existing images need to be regenerated after changing this value.'=>'Width of the agnosis-artwork image size used in post content and lightbox. Height scales proportionally. Default: 1920. Existing images need to be regenerated after changing this value.','Thumbnail size (px)'=>'Thumbnail size (px)','Side length of the square agnosis-thumb size used in submission cards and dashboard. Default: 512. Existing images need to be regenerated after changing this value.'=>'Side length of the square agnosis-thumb size used in submission cards and dashboard. Default: 512. Existing images need to be regenerated after changing this value.','Email image width (px)'=>'Email image width (px)','Width of the agnosis-email size used in artist notification emails. Height scales proportionally — no cropping. Default: 420. Existing images need to be regenerated after changing this value.'=>'Width of the agnosis-email size used in artist notification emails. Height scales proportionally — no cropping. Default: 420. Existing images need to be regenerated after changing this value.','Gallery overview — items per page'=>'Gallery overview — items per page','How many artwork cards the gallery overview shows per page. Pool is built proportionally across all artists; featured artworks are preferred. Default: 12.'=>'How many artwork cards the gallery overview shows per page. Pool is built proportionally across all artists; featured artworks are preferred. Default: 12.','Review link expiry (days)'=>'Review link expiry (days)','How long the Approve & Publish / Discard links in a submission review email stay valid before an artist has to log in to manage the item instead. Applies uniformly to artwork, biography, and event drafts. Default: 7.'=>'How long the Approve & Publish / Discard links in a submission review email stay valid before an artist has to log in to manage the item instead. Applies uniformly to artwork, biography, and event drafts. Default: 7.','System prompt'=>'System prompt','Sent to the AI as the system instruction. Use {tag_count} and {excerpt_words} as tokens — they are replaced with the values below.'=>'Sent to the AI as the system instruction. Use {tag_count} and {excerpt_words} as tokens — they are replaced with the values below.','Artist prompt template'=>'Artist prompt template','User message sent alongside the artwork image. Use {artist_prompt} where the artist\'s own description should appear.'=>'User message sent alongside the artwork image. Use {artist_prompt} where the artist\'s own description should appear.','Enhancement instructions'=>'Enhancement instructions','Instructions passed to the image enhancement provider. The AI-generated artwork description is appended automatically as context.'=>'Instructions passed to the image enhancement provider. The AI-generated artwork description is appended automatically as context.','Number of tags'=>'Number of tags','How many tags the AI should generate per artwork. Referenced as {tag_count} in the system prompt.'=>'How many tags the AI should generate per artwork. Referenced as {tag_count} in the system prompt.','Excerpt word limit'=>'Excerpt word limit','Maximum words for the one-sentence excerpt. Referenced as {excerpt_words} in the system prompt.'=>'Maximum words for the one-sentence excerpt. Referenced as {excerpt_words} in the system prompt.','Trust all admitted artists (skip link review entirely)'=>'Trust all admitted artists (skip link review entirely)','Every artist here was already vouched in by the community — if that trust is enough for you, turn this on to embed any link an artist submits, immediately, with no allowlist check and no AI review at all (the settings below are skipped entirely while this is on). Off by default. Only enable this if you are comfortable that a bad actor who made it through admission could embed a link to anything.'=>'Every artist here was already vouched in by the community — if that trust is enough for you, turn this on to embed any link an artist submits, immediately, with no allowlist check and no AI review at all (the settings below are skipped entirely while this is on). Off by default. Only enable this if you are comfortable that a bad actor who made it through admission could embed a link to anything.','Trusted embed platforms'=>'Trusted embed platforms','One hostname per line. A submitted link becomes a rich embed immediately if it matches one of these (or a subdomain of one) — no AI review needed, no network request made to the link itself.'=>'One hostname per line. A submitted link becomes a rich embed immediately if it matches one of these (or a subdomain of one) — no AI review needed, no network request made to the link itself.','Let artists submit other links too (AI-reviewed)'=>'Let artists submit other links too (AI-reviewed)','When enabled, a link to a site not on the trusted list above is not simply discarded: the destination page is fetched and reviewed by your configured AI provider (Settings → AI Providers) against the categories below before deciding whether to embed it. If the AI cannot be reached, the request times out, or the page cannot be safely fetched, the link is not embedded — it fails safe. When disabled (the default), only the trusted platforms above are ever embedded.'=>'When enabled, a link to a site not on the trusted list above is not simply discarded: the destination page is fetched and reviewed by your configured AI provider (Settings → AI Providers) against the categories below before deciding whether to embed it. If the AI cannot be reached, the request times out, or the page cannot be safely fetched, the link is not embedded — it fails safe. When disabled (the default), only the trusted platforms above are ever embedded.','Block pornographic / sexually explicit content'=>'Block pornographic / sexually explicit content','Only takes effect when AI review (above) is enabled.'=>'Only takes effect when AI review (above) is enabled.','Block primarily commercial / promotional sites'=>'Block primarily commercial / promotional sites','Online stores, advertising, marketing landing pages. Off by default — an artist linking to a shop selling their own prints is common and not inherently unwanted. Only takes effect when AI review (above) is enabled.'=>'Online stores, advertising, marketing landing pages. Off by default — an artist linking to a shop selling their own prints is common and not inherently unwanted. Only takes effect when AI review (above) is enabled.','Block gambling / betting sites'=>'Block gambling / betting sites','Additional disallowed categories'=>'Additional disallowed categories','Optional — describe any other kind of content the AI should reject, in plain language (e.g. "hate speech or violent extremist content", "phishing or scam pages"). Only takes effect when AI review (above) is enabled.'=>'Optional — describe any other kind of content the AI should reject, in plain language (e.g. "hate speech or violent extremist content", "phishing or scam pages"). Only takes effect when AI review (above) is enabled.','Node label'=>'Node label','How this node introduces itself to the network.'=>'How this node introduces itself to the network.','Enable ActivityPub federation'=>'Enable ActivityPub federation','Broadcast new artworks to Mastodon, Pixelfed and the Fediverse.'=>'Broadcast new artworks to Mastodon, Pixelfed, and the Fediverse.','Node public key'=>'Node public key','Auto-generated RSA public key for this node. Share this with peer nodes.'=>'Auto-generated RSA public key for this node. Share this with peer nodes.','Self-removal (goodbye) requests per sender per day'=>'Self-removal (goodbye) requests per sender per day','Maximum number of self-removal ("goodbye") confirmation emails a single sender address can trigger per day. A genuine self-removal only ever needs to be requested once — this caps how many confirmation emails a spoofed or repeated From can be used to spam a real artist with. Default: 3.'=>'Maximum number of self-removal ("goodbye") confirmation emails a single sender address can trigger per day. A genuine self-removal only ever needs to be requested once — this caps how many confirmation emails a spoofed or repeated From can be used to spam a real artist with. Default: 3.','Community broadcasts per artist per day'=>'Community broadcasts per artist per day','Maximum number of messages a single artist can send to the Community announcement address (Settings → Email) per day. Prevents one member from flooding every other member\'s inbox. Default: 3.'=>'Maximum number of messages a single artist can send to the Community announcement address (Settings → Email) per day. Prevents one member from flooding every other member\'s inbox. Default: 3.','Community broadcast max length (characters)'=>'Community broadcast max length (characters)','Longer messages to the Community announcement address are bounced back to the sender instead of being broadcast — the sender is told to shorten it and resend. Measured in characters, not words, so it applies fairly across languages that don\'t use spaces between words (Chinese, Japanese, Thai, etc.). Every recipient\'s copy is translated individually, so this also caps how much a single message can cost in AI translation calls. Default: 2000. Hard maximum: 20000, regardless of this setting.'=>'Longer messages to the Community announcement address are bounced back to the sender instead of being broadcast — the sender is told to shorten it and resend. Measured in characters, not words, so it applies fairly across languages that don\'t use spaces between words (Chinese, Japanese, Thai, etc.). Every recipient\'s copy is translated individually, so this also caps how much a single message can cost in AI translation calls. Default: 2000. Hard maximum: 20000, regardless of this setting.','Admission vote threshold (%)'=>'Admission vote threshold (%)','Percentage of active artists that must vote yes for admission. Combined with the minimum floor below.'=>'Percentage of active artists that must vote yes for admission. Combined with the minimum floor below.','Admission minimum votes'=>'Admission minimum votes','Absolute minimum positive votes required regardless of the percentage above.'=>'Absolute minimum positive votes required regardless of the percentage above.','Voting window (days)'=>'Voting window (days)','Days an application stays open. If the threshold is not reached within this window the application is rejected.'=>'Days an application stays open. If the threshold is not reached within this window the application is rejected.','Resolved application retention (days)'=>'Resolved application retention (days)','A rejected, withdrawn, or left application\'s email, name, biography, statement, and portfolio link are anonymized by the daily cleanup after this many days — the application record itself (status and dates) is kept for admission history. A banned artist\'s biography/statement/portfolio are anonymized on the same schedule, but their email is deliberately kept so the ban stays enforceable. Default: 180 days.'=>'A rejected, withdrawn, or left application\'s email, name, biography, statement, and portfolio link are anonymized by the daily cleanup after this many days — the application record itself (status and dates) is kept for admission history. A banned artist\'s biography/statement/portfolio are anonymized on the same schedule, but their email is deliberately kept so the ban stays enforceable. Default: 180 days.','After applying, send artists to'=>'After applying, send artists to','Optional — pick a page explaining the vouching process and what happens next. When the application is submitted successfully, the artist is redirected there instead of just seeing an inline confirmation message. Leave as "None" to keep the inline message only.'=>'Optional — pick a page explaining the vouching process and what happens next. When the application is submitted successfully, the artist is redirected there instead of just seeing an inline confirmation message. Leave as "None" to keep the inline message only.','Community size cap'=>'Community size cap','Maximum number of admitted artists. When full, new applications join a waitlist instead of being rejected, and a freed slot admits the next in line. Set to 0 for no cap. The community can also vote to change this.'=>'Maximum number of admitted artists. When full, new applications join a waitlist instead of being rejected, and a freed slot admits the next in line. Set to 0 for no cap. The community can also vote to change this.','Cap-change co-signers required'=>'Cap-change co-signers required','How many artists must co-sign a proposal to change the community size cap before it opens as a full community vote.'=>'How many artists must co-sign a proposal to change the community size cap before it opens as a full community vote.','Cap-change vote window (days)'=>'Cap-change vote window (days)','Days a community cap-change vote stays open. A strict majority of active artists voting yes adopts the new cap.'=>'Days a community cap-change vote stays open. A strict majority of active artists voting yes adopts the new cap.','Removal nominations required'=>'Removal nominations required','Number of artist nominations needed before a community removal vote opens. Admins can bypass this threshold.'=>'Number of artist nominations needed before a community removal vote opens. Admins can bypass this threshold.','Removal vote window (days)'=>'Removal vote window (days)','Days a community removal vote stays open. A majority (>50%) of active artists must vote yes for removal to proceed.'=>'Days a community removal vote stays open. A majority (>50%) of active artists must vote yes for removal to proceed.','Invitation intro'=>'Invitation intro','Agnosis is a small, self-hosted home for artists who\'d rather make work than manage a platform. There\'s no algorithm deciding who sees your art, no portfolio site to maintain, and no account to configure — just your work, published and translated automatically for a global audience.

Being part of the community is simple: Fellow artists vouch for new applicants, and everyone keeps full ownership of what they publish; you can leave at any time and take your work with you.

Once admitted, you submit new work by sending it as an email — no dashboard, no forms and you can update, promote or remove your artwork as well sending an email. You can find more information visiting the agnosis.art website.'=>'Agnosis is a small, self-hosted home for artists who\'d rather make work than manage a platform. There\'s no algorithm deciding who sees your art, no portfolio site to maintain, and no account to configure — just your work, published and translated automatically for a global audience.

Being part of the community is simple: Fellow artists vouch for new applicants, and everyone keeps full ownership of what they publish; you can leave at any time and take your work with you.

Once admitted, you submit new work by sending it as an email — no dashboard, no forms and you can update, promote or remove your artwork as well sending an email. You can find more information visiting the agnosis.art website.','Shown near the top of the "Send Invitation" email below (an "Apply to join" link and site name follow automatically — no need to add either here). Two or three short paragraphs is plenty. Standing copy, not cleared after use like the newsletter intros above — translated automatically when an invitation is sent in a language other than the site\'s own.'=>'Shown near the top of the "Send Invitation" email below (an "Apply to join" link and site name follow automatically — no need to add either here). Two or three short paragraphs is plenty. Standing copy, not cleared after use like the newsletter intros above — translated automatically when an invitation is sent in a language other than the site\'s own.','Transaction fee (%)'=>'Transaction fee (%)','Percentage retained by this node on donations and art sales. Artists pay nothing up front.'=>'Percentage retained by this node on donations and art sales. Artists pay nothing up front.','Sender name'=>'Sender name','Name shown as the sender of digest emails. Leave blank to use the site name.'=>'Name shown as the sender of digest emails. Leave blank to use the site name.','Sender email address'=>'Sender email address','Dedicated From: address for both newsletters, e.g. newsletter@agnosis.art — keeps digest mail separate from the site\'s admin email for deliverability and so artists can filter it. Leave blank to use the admin email. Must be a valid, deliverable address on your domain (SPF/DKIM configured) or messages may be marked as spam.'=>'Dedicated From: address for both newsletters, e.g. newsletter@agnosis.art — keeps digest mail separate from the site\'s admin email for deliverability and so artists can filter it. Leave blank to use the admin email. Must be a valid, deliverable address on your domain (SPF/DKIM configured) or messages may be marked as spam.','Auto-draft newsletter intros'=>'Auto-draft newsletter intros','When enabled, Agnosis drafts an intro via AI ahead of each issue (see the lead time below), saves it to that newsletter\'s intro field, and emails you to review it — unless you\'ve already written one for that cycle. Disable to leave both intro fields exactly as you left them, always.'=>'When enabled, Agnosis drafts an intro via AI ahead of each issue (see the lead time below), saves it to that newsletter\'s intro field, and emails you to review it — unless you\'ve already written one for that cycle. Disable to leave both intro fields exactly as you left them, always.','Draft intro this many hours ahead'=>'Draft intro this many hours ahead','How long before an issue is due Agnosis proposes an AI-drafted intro. Only takes effect when auto-drafting (above) is enabled. Default: 24.'=>'How long before an issue is due Agnosis proposes an AI-drafted intro. Only takes effect when auto-drafting (above) is enabled. Default: 24.','Artist newsletter'=>'Artist newsletter','Admitted artists are auto-enrolled (they can unsubscribe from any issue with one click). Community digest: recent activity, new members, open votes.'=>'Admitted artists are auto-enrolled (they can unsubscribe from any issue with one click). Community digest: recent activity, new members, open votes.','Artist newsletter frequency (days)'=>'Artist newsletter frequency (days)','Default 30 ≈ monthly. A new issue is prepared once this many days have passed since the last one was sent.'=>'Default 30 ≈ monthly. A new issue is prepared once this many days have passed since the last one was sent.','Artist newsletter intro'=>'Artist newsletter intro','Optional note prepended to the next artist issue only — cleared automatically once that issue is queued. Leave blank to send the auto-digest with no intro. If left blank, Agnosis drafts one automatically from what\'s new about a day before the issue sends, and emails you to review it first — write your own here any time to skip that.'=>'Optional note prepended to the next artist issue only — cleared automatically once that issue is queued. Leave blank to send the auto-digest with no intro. If left blank, Agnosis drafts one automatically from what\'s new about a day before the issue sends, and emails you to review it first — write your own here any time to skip that.','Public newsletter'=>'Public newsletter','Visitors subscribe via the agnosis/newsletter-signup block (double opt-in). Digest: new artwork and events published since the last issue.'=>'Visitors subscribe via the agnosis/newsletter-signup block (double opt-in). Digest: new artwork and events published since the last issue.','Public newsletter frequency (days)'=>'Public newsletter frequency (days)','Default 30 ≈ monthly.'=>'Default 30 ≈ monthly.','Public newsletter intro'=>'Public newsletter intro','Optional note prepended to the next public issue only — cleared automatically once that issue is queued. If left blank, Agnosis drafts one automatically from what\'s new about a day before the issue sends, and emails you to review it first — write your own here any time to skip that.'=>'Optional note prepended to the next public issue only — cleared automatically once that issue is queued. If left blank, Agnosis drafts one automatically from what\'s new about a day before the issue sends, and emails you to review it first — write your own here any time to skip that.','Send batch size'=>'Send batch size','Recipients emailed per 5-minute cron tick. Lower this if your host throttles outbound mail; raise it for faster delivery on hosts with generous limits.'=>'Recipients emailed per 5-minute cron tick. Lower this if your host throttles outbound mail; raise it for faster delivery on hosts with generous limits.','Self-hosting comfort threshold'=>'Self-hosting comfort threshold','Advisory only — self-hosted sending keeps working above this count. Once confirmed public subscribers pass it, this page shows a reminder to consider an email service provider (e.g. Brevo\'s free tier) instead.'=>'Advisory only — self-hosted sending keeps working above this count. Once confirmed public subscribers pass it, this page shows a reminder to consider an email service provider (e.g. Brevo\'s free tier) instead.','Sends a minimal ping ("Reply with the word: ping") using the configured API key.'=>'Sends a minimal ping ("Reply with the word: ping") using the configured API key.','Sends a minimal ping using the configured API key.'=>'Sends a minimal ping using the configured API key.','WordPress AI Client'=>'WordPress AI Client','Checks that wp_ai_client_prompt() is available (WordPress 7.0+) and a text-generation model is configured.'=>'Checks that wp_ai_client_prompt() is available (WordPress 7.0+) and a text-generation model is configured.','Test AI Providers'=>'Test AI Providers','Test %s'=>'Test %s','Bot Protection'=>'Bot Protection','Turnstile is configured.'=>'Turnstile is configured.','The Join application form and the Newsletter Subscribe form both require human verification before they accept a submission.'=>'The Join application form and the Newsletter Subscribe form both require human verification before they accept a submission.','Turnstile is not configured.'=>'Turnstile is not configured.','Your Join application form is public — anyone can submit an application, and a submitted (and confirmed) application still emails every admitted artist and admin. Right now the only thing standing between that form and an automated bot is a fixed 5-submissions-per-minute-per-IP limit, which a distributed bot can work around entirely. Add a Cloudflare Turnstile site key and secret key above to require human verification on both the Join form and the Newsletter Subscribe form.'=>'Your Join application form is public — anyone can submit an application, and a submitted (and confirmed) application still emails every admitted artist and admin. Right now the only thing standing between that form and an automated bot is a fixed 5-submissions-per-minute-per-IP limit, which a distributed bot can work around entirely. Add a Cloudflare Turnstile site key and secret key above to require human verification on both the Join form and the Newsletter Subscribe form.','OpenAI'=>'OpenAI','Anthropic'=>'Anthropic','AI Processing & Privacy Policy'=>'AI Processing & Privacy Policy','A Privacy Policy page is set.'=>'A Privacy Policy page is set.','Suggested wording covering %s and public federation was added to it automatically — review it under Settings → Privacy → "Guide" before publishing, and check with your provider(s) about their own data processing agreement (DPA) for your compliance obligations.'=>'Suggested wording covering %s and public federation was added to it automatically — review it under Settings → Privacy → "Guide" before publishing, and check with your provider(s) about their own data processing agreement (DPA) for your compliance obligations.','No Privacy Policy page is set.'=>'No Privacy Policy page is set.','Submitted artwork, text, and visitor contact messages are sent to %s for processing. Create or choose a page under Settings → Privacy — this plugin has already prepared suggested wording you\'ll find there under "Guide". You may also want to review that provider\'s data processing agreement (DPA) for your own compliance obligations.'=>'Submitted artwork, text, and visitor contact messages are sent to %s for processing. Create or choose a page under Settings → Privacy — this plugin has already prepared suggested wording you\'ll find there under "Guide". You may also want to review that provider\'s data processing agreement (DPA) for your own compliance obligations.','Go to Settings → Privacy'=>'Go to Settings → Privacy','Debug Files'=>'Debug Files','Currently'=>'Currently','Enabled'=>'Enabled','Disabled'=>'Disabled','Forced ON by the AGNOSIS_DEBUG constant in wp-config.php — the checkbox above has no effect until that line is removed.'=>'Forced ON by the AGNOSIS_DEBUG constant in wp-config.php — the checkbox above has no effect until that line is removed.','Forced OFF by the AGNOSIS_DEBUG constant in wp-config.php — the checkbox above has no effect until that line is removed.'=>'Forced OFF by the AGNOSIS_DEBUG constant in wp-config.php — the checkbox above has no effect until that line is removed.','Directory'=>'Directory','Filter with agnosis_debug_dir to redirect debug output elsewhere.'=>'Filter with agnosis_debug_dir to redirect debug output elsewhere.','.txt file(s) in the directory'=>'.txt file(s) in the directory','Delete all .txt files in the debug directory? The directory itself stays in place so future debug writes still land cleanly.'=>'Delete all .txt files in the debug directory? The directory itself stays in place so future debug writes still land cleanly.','Clear Debug Files'=>'Clear Debug Files','Term Translation Cache'=>'Term Translation Cache','Cached translations'=>'Cached translations','AI-translated tag/medium term names, cached so the same term always gets the same translated label instead of a fresh AI phrasing per post. Renaming a term already clears its own cached entry automatically; use the button below only if a cached translation itself is wrong.'=>'AI-translated tag/medium term names, cached so the same term always gets the same translated label instead of a fresh AI phrasing per post. Renaming a term already clears its own cached entry automatically; use the button below only if a cached translation itself is wrong.','Clear every cached term translation? Nothing is deleted from your site — terms will simply be re-translated by AI the next time they\'re needed.'=>'Clear every cached term translation? Nothing is deleted from your site — terms will simply be re-translated by AI the next time they\'re needed.','Clear Term Translation Cache'=>'Clear Term Translation Cache','Pipeline Logs'=>'Pipeline Logs','Clear all log entries?'=>'Clear all log entries?','Clear All'=>'Clear All','%d entries total. Logs are pruned automatically according to the Inbox retention setting.'=>'%d entries total. Logs are pruned automatically according to the Inbox retention setting.','No log entries yet.'=>'No log entries yet.','Time'=>'Time','Level'=>'Level','Context'=>'Context','Inbox Tools'=>'Inbox Tools','Test connection'=>'Test connection','Test IMAP Connection'=>'Test IMAP Connection','Connects to the configured mailbox and reports the total and unseen message count.'=>'Connects to the configured mailbox and reports the total and unseen message count.','Poll inbox now'=>'Poll inbox now','Poll Inbox Now'=>'Poll Inbox Now','Fetches unseen messages immediately without waiting for WP-Cron. Then click "Process Pending Queue" to run the AI pipeline.'=>'Fetches unseen messages immediately without waiting for WP-Cron. Then click "Process Pending Queue" to run the AI pipeline.','Process queue'=>'Process queue','Process Pending Queue'=>'Process Pending Queue','Immediately runs the AI pipeline on all pending queue items without waiting for WP-Cron. Use this to test the end-to-end flow after a poll.'=>'Immediately runs the AI pipeline on all pending queue items without waiting for WP-Cron. Use this to test the end-to-end flow after a poll.','Force reprocess'=>'Force reprocess','Force Reprocess Inbox'=>'Force Reprocess Inbox','Resets failed/stuck/orphaned queue rows back to pending, then immediately polls for unprocessed messages. Then click "Process Pending Queue" to run the AI pipeline. Already-published artworks with valid posts are never re-processed.'=>'Resets failed/stuck/orphaned queue rows back to pending, then immediately polls for unprocessed messages. Then click "Process Pending Queue" to run the AI pipeline. Already-published artworks with valid posts are never re-processed.','Deliverability'=>'Deliverability','A diagnostic check only — nothing here changes how mail is sent. On ordinary hosting (PHP mail(), no SMTP plugin), mail sent from an address that doesn\'t match your site\'s own domain, or from a domain with no SPF/DMARC record at all, is increasingly likely to land in spam or be rejected outright by large mailbox providers. If any row below looks wrong, the most reliable fix is installing an SMTP-sending plugin (WP Mail SMTP, Post SMTP, FluentSMTP, and others all work) configured against a real transactional mail provider, and adding SPF/DMARC records for the domain you send from at your DNS host.'=>'A diagnostic check only — nothing here changes how mail is sent. On ordinary hosting (PHP mail(), no SMTP plugin), mail sent from an address that doesn\'t match your site\'s own domain, or from a domain with no SPF/DMARC record at all, is increasingly likely to land in spam or be rejected outright by large mailbox providers. If any row below looks wrong, the most reliable fix is installing an SMTP-sending plugin (WP Mail SMTP, Post SMTP, FluentSMTP, and others all work) configured against a real transactional mail provider, and adding SPF/DMARC records for the domain you send from at your DNS host.','From identity'=>'From identity','Domain matches site?'=>'Domain matches site?','SPF record'=>'SPF record','DMARC record'=>'DMARC record','SMTP plugin'=>'SMTP plugin','Detected: %s'=>'Detected: %s','None of the common SMTP-sending plugins were detected — this site is likely relying on PHP\'s built-in mail(), which most hosts deliver poorly through.'=>'None of the common SMTP-sending plugins were detected — this site is likely relying on PHP\'s built-in mail(), which most hosts deliver poorly through.','Send a real test email to:'=>'Send a real test email to:','Send Test'=>'Send Test','Sends one plain-text email from the same community identity used for review/vote/vouch mail. Reaching your inbox is a good sign; landing in spam or not arriving at all confirms a real deliverability problem regardless of what the checks above say.'=>'Sends one plain-text email from the same community identity used for review/vote/vouch mail. Reaching your inbox is a good sign; landing in spam or not arriving at all confirms a real deliverability problem regardless of what the checks above say.','Found'=>'Found','Not found'=>'Not found','DNS lookup failed'=>'DNS lookup failed','Unavailable on this host'=>'Unavailable on this host','No address configured'=>'No address configured','[TEST] Deliverability check from %s'=>'[TEST] Deliverability check from %s','This is a one-off deliverability test from your Agnosis Settings → Email Inbox page. If you\'re reading this in your inbox (not spam), the community/transactional From identity is deliverable to this address.'=>'This is a one-off deliverability test from your Agnosis Settings → Email Inbox page. If you\'re reading this in your inbox (not spam), the community/transactional From identity is deliverable to this address.','Pending Applications'=>'Pending Applications','%d application is awaiting email confirmation from the applicant and isn\'t listed below yet.'=>'%d application is awaiting email confirmation from the applicant and isn\'t listed below yet.' . "\0" . '%d applications are awaiting email confirmation from the applicant and aren\'t listed below yet.','No pending applications.'=>'No pending applications.','%d positive vote(s) currently required for admission.'=>'%d positive vote(s) currently required for admission.','Applicant'=>'Applicant','Applied'=>'Applied','Votes'=>'Votes','Bio / Portfolio'=>'Bio / Portfolio','%1$d / %2$d'=>'%1$d / %2$d','Portfolio ↗'=>'Portfolio ↗','Admit'=>'Admit','Reject'=>'Reject','No admitted members yet.'=>'No admitted members yet.','Joined'=>'Joined','Banned until %s'=>'Banned until %s','Banned'=>'Banned','Active'=>'Active','This address has bounced or been reported as spam — mail may no longer be reaching this artist.'=>'This address has bounced or been reported as spam — mail may no longer be reaching this artist.','⚠ %d bounce'=>'⚠ %d bounce' . "\0" . '⚠ %d bounce